// Some portions generated by Claude Code
package org.eclipse.rdf4j.sail.lmdb.evaluation;

import static org.assertj.core.api.Assertions.assertThat;

import org.junit.jupiter.api.Test;

/**
 * Unit spec for {@link NativeGroupIteration#reshapeLeftJoinForFactorization}: hoisting OPTIONAL-independent bag members
 * above the LeftJoin must not discard the compiler's selective child order. The LeftJoin composite takes the position
 * of the first kept child; every hoisted member keeps its original relative position. Placing the composite first
 * (regardless of where its kept children sat) makes the unbounded OPTIONAL scan the prefix driver and demotes the
 * selective members — the ELECTRICAL_GRID#2 ~700x regression.
 */
public class LmdbNativeLeftJoinReshapeOrderTest {

	private static final int NAME = 0;
	private static final int SUBSTATION = 1;
	private static final int TRANSFORMER = 2;
	private static final int METER = 3;

	private static PatternPlan pattern(Term s, Term o, double estimate) {
		return new PatternPlan(s, Term.constant(7), o, Term.unbound(), ContextConstraint.UNRESTRICTED, false, estimate);
	}

	private static ValuesPlan values(int slot, long... ids) {
		ValuesRow[] rows = new ValuesRow[ids.length];
		for (int i = 0; i < ids.length; i++) {
			rows[i] = new ValuesRow(new int[] { slot }, new long[] { ids[i] });
		}
		return new ValuesPlan(rows);
	}

	@Test
	public void compositeTakesFirstKeptChildPositionAndHoistedMembersKeepOrder() {
		ValuesPlan names = values(NAME, 101, 102, 103);
		PatternPlan namePattern = pattern(Term.slot(SUBSTATION), Term.slot(NAME), 9_400);
		PatternPlan feeds = pattern(Term.slot(TRANSFORMER), Term.slot(SUBSTATION), 37_000);
		PatternPlan type = pattern(Term.slot(TRANSFORMER), Term.constant(999), 28_000);
		PatternPlan hasMeter = pattern(Term.slot(TRANSFORMER), Term.slot(METER), 112_000);

		LeftJoinPlan leftJoin = new LeftJoinPlan(
				new MultiJoinPlan(new SlotPlan[] { names, namePattern, feeds, type }, new MaskedFilter[0]), hasMeter);

		MultiJoinPlan reshaped = NativeGroupIteration.reshapeLeftJoinForFactorization(leftJoin);

		assertThat(reshaped).isNotNull();
		assertThat(reshaped.children).hasSize(4);
		// the OPTIONAL only reads ?transformer, so feeds is the single kept child: the composite takes
		// feeds' position while the selective VALUES-driven members stay in front of it
		assertThat(reshaped.children[0]).isSameAs(names);
		assertThat(reshaped.children[1]).isSameAs(namePattern);
		assertThat(reshaped.children[2]).isInstanceOf(LeftJoinPlan.class);
		LeftJoinPlan composite = (LeftJoinPlan) reshaped.children[2];
		assertThat(composite.left).isSameAs(feeds);
		assertThat(composite.right).isSameAs(hasMeter);
		assertThat(reshaped.children[3]).isSameAs(type);
	}

	@Test
	public void multiChildKeepSetAnchorsAtItsFirstMember() {
		ValuesPlan names = values(NAME, 101);
		PatternPlan namePattern = pattern(Term.slot(SUBSTATION), Term.slot(NAME), 9_400);
		PatternPlan feeds = pattern(Term.slot(TRANSFORMER), Term.slot(SUBSTATION), 37_000);
		PatternPlan type = pattern(Term.slot(TRANSFORMER), Term.constant(999), 28_000);
		// the OPTIONAL reads both ?substation and ?transformer: keep = {namePattern, feeds}
		PatternPlan optional = pattern(Term.slot(TRANSFORMER), Term.slot(SUBSTATION), 112_000);

		LeftJoinPlan leftJoin = new LeftJoinPlan(
				new MultiJoinPlan(new SlotPlan[] { names, namePattern, feeds, type }, new MaskedFilter[0]), optional);

		MultiJoinPlan reshaped = NativeGroupIteration.reshapeLeftJoinForFactorization(leftJoin);

		assertThat(reshaped).isNotNull();
		assertThat(reshaped.children).hasSize(3);
		assertThat(reshaped.children[0]).isSameAs(names);
		assertThat(reshaped.children[1]).isInstanceOf(LeftJoinPlan.class);
		LeftJoinPlan composite = (LeftJoinPlan) reshaped.children[1];
		assertThat(composite.left).isInstanceOf(MultiJoinPlan.class);
		assertThat(((MultiJoinPlan) composite.left).children).containsExactly(namePattern, feeds);
		assertThat(composite.right).isSameAs(optional);
		assertThat(reshaped.children[2]).isSameAs(type);
	}

	@Test
	public void keepSetStartingAtFirstChildKeepsCompositeFirst() {
		PatternPlan feeds = pattern(Term.slot(TRANSFORMER), Term.slot(SUBSTATION), 37_000);
		PatternPlan type = pattern(Term.slot(TRANSFORMER), Term.constant(999), 28_000);
		PatternPlan hasMeter = pattern(Term.slot(TRANSFORMER), Term.slot(METER), 112_000);

		LeftJoinPlan leftJoin = new LeftJoinPlan(
				new MultiJoinPlan(new SlotPlan[] { feeds, type }, new MaskedFilter[0]), hasMeter);

		MultiJoinPlan reshaped = NativeGroupIteration.reshapeLeftJoinForFactorization(leftJoin);

		assertThat(reshaped).isNotNull();
		assertThat(reshaped.children).hasSize(2);
		assertThat(reshaped.children[0]).isInstanceOf(LeftJoinPlan.class);
		LeftJoinPlan composite = (LeftJoinPlan) reshaped.children[0];
		assertThat(composite.left).isSameAs(feeds);
		assertThat(composite.right).isSameAs(hasMeter);
		assertThat(reshaped.children[1]).isSameAs(type);
	}
}
